using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // ── CalculateTotal: DataRow tests ────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.10, 0.00, DisplayName = "Zero unit price")]
    [DataRow(10.00, 0, 0.10, 0.00, DisplayName = "Zero quantity")]
    [DataRow(99.99, 1, 1.0, 199.98, DisplayName = "Max tax rate (100%)")]
    public void CalculateTotal_WithVariousInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── CalculateTotal: DynamicData with ValueTuples ─────────────────────

    [TestMethod]
    [DynamicData(nameof(CalculateTotalData))]
    public void CalculateTotal_DynamicData_ReturnsExpectedTotal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, decimal expected)> CalculateTotalData =>
    [
        (10.00m, 2, 0.0m, 20.00m),
        (15.00m, 4, 0.05m, 63.00m),
        (100.00m, 1, 0.25m, 125.00m),
        (0.01m, 100, 0.10m, 1.10m),
    ];

    // ── CalculateTotal: invalid inputs ───────────────────────────────────

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    public void CalculateTotal_WithNegativeInputs_ThrowsArgumentOutOfRangeException(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below 0")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_WithInvalidTaxRate_ThrowsArgumentOutOfRangeException(
        double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));
    }

    // ── ApplyDiscount: DataRow tests ─────────────────────────────────────

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off 100")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% off 200")]
    [DataRow(50.00, 0.0, 50.00, DisplayName = "No discount")]
    [DataRow(80.00, 100.0, 0.00, DisplayName = "100% discount (free)")]
    [DataRow(49.99, 50.0, 24.995, DisplayName = "50% off fractional price")]
    public void ApplyDiscount_WithVariousInputs_ReturnsExpectedPrice(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── ApplyDiscount: DynamicData with ValueTuples ──────────────────────

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountData))]
    public void ApplyDiscount_DynamicData_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> ApplyDiscountData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (999.99m, 15m, 849.9915m),
        (0m, 50m, 0m),
    ];

    // ── ApplyDiscount: invalid inputs ────────────────────────────────────

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Discount below 0%")]
    [DataRow(100.01, DisplayName = "Discount above 100%")]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRangeException(
        double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    // ── FormatPrice: DataRow tests ───────────────────────────────────────

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "USD format")]
    [DataRow(19.99, "€", "€19.99", DisplayName = "Euro format")]
    [DataRow(1000.00, "$", "$1000.00", DisplayName = "Large value")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    public void FormatPrice_WithVariousInputs_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

